/** Superbits that DOUBLE a specific colour's bonus (`*(2+0.5*SuperBitType(59))`, N.js:17768),
 *  cross-referenced against gamedata-w5-gaming.mjs's SUPERBITS table and bonuses/gaming.mjs's
 *  PALETTE_SUPERBIT_GATE (which already had this exact mapping — confirmed match, no discrepancy):
 *    colour 25 "Peachy_Pink"  <- superbit 49 "Peachier_Peach"
 *    colour 13 "Ocean_Blue"   <- superbit 51 "Bluer_Ocean"
 *    colour 31 "Red_Orange"   <- superbit 52 "Redder_Orange"
 *    colour 18 "Offwhite"     <- superbit 54 "Further_Offcolour"
 *    colour  3 "Neon_Tree"    <- superbit 58 "Everybody_Talks"
 *    colour 12 "Babby_Blue"   <- superbit 61 "Babbiest_Blue"
 *  superbit 59 "Colourier_Colours" is the shared "+0.5" upgrade (turns the above from x2 to x2.5).
 *  superbit 42 "Bigger_Palette" additionally grants +1 total palette colour SLOT and 2x total
 *  Palette Luck (its own description, not a per-colour doubler). */
export const PALETTE_SUPERBIT_DOUBLE = { 25: 49, 13: 51, 31: 52, 18: 54, 3: 58, 12: 61 };
export const PALETTE_SUPERBIT_DOUBLE_PLUS = 59;
export const PALETTE_SUPERBIT_EXTRA_SLOT = 42;

/* PaletteBonus(g)==d builder, N.js:17766-17770 (verbatim). Rebuilds the WHOLE 37-entry
 * PaletteBonz array (+ a 38th "total colour levels" entry at index 37) whenever called with
 * b==-1 or the cache is missing; otherwise returns the cached PaletteBonz[b]:
 *   for g in 0..36:
 *     base = GamingPalette[g].curve==1
 *              ? Spelunk[9][g]/(Spelunk[9][g]+25) * GamingPalette[g].cap     // soft-cap curve
 *              : Spelunk[9][g] * GamingPalette[g].cap                        // linear
 *     PaletteDNz += Spelunk[9][g]                          // running total colour LEVELS
 *     if g in PALETTE_SUPERBIT_DOUBLE and that gate superbit owned:
 *       base *= (2 + 0.5*SuperBitType(PALETTE_SUPERBIT_DOUBLE_PLUS))
 *     base *= (1 + Thingies("LegendPTS_bonus",10,0)/100)     // Picasso_Gaming legend talent
 *     base *= (1 + 0.5*Spelunk("DoWeHaveLoreN1",8,0))        // lore book 8 -> x1.5
 *     PaletteBonz[g] = base
 *   PaletteBonz[37] = round(PaletteDNz)     // "Total Colour Levels", read back as PaletteBonus(37)
 *   return b==-1 ? 0 : PaletteBonz[b]
 * This matches bonuses/gaming.mjs's `paletteBonus()` implementation exactly (that file already
 * has PALETTE_ROWS[5] = {cap:300, soft:25} verified against GamingPalette[5] = {cap:300,curve:1}
 * above — confirmed, no discrepancy) — this file adds the remaining 36 rows' cap/curve so
 * bonuses/gaming.mjs can extend PALETTE_ROWS to any of the 37 colours without re-deriving them. */
export function paletteBonusBase(g, spelunkLevel) {
  const row = GAMING_PALETTE[g];
  return row.curve === 1
    ? (spelunkLevel / (spelunkLevel + 25)) * row.cap
    : spelunkLevel * row.cap;
}

/* LVupChance(g)==d, N.js:17770: PaletteLuck() * (1 / (lvA * max(1.2, lvB-0.05)^Spelunk[9][g])))
 * PalUnlockChance(g)==d, N.js:17770-17771: PaletteLuck() * (1 / unlockDiv) */
export function paletteLVupChance(paletteLuckValue, g, spelunkLevel) {
  const row = GAMING_PALETTE[g];
  return paletteLuckValue * (1 / (row.lvA * Math.pow(Math.max(1.2, row.lvB - 0.05), spelunkLevel)));
}
export function palUnlockChance(paletteLuckValue, g) {
  return paletteLuckValue * (1 / GAMING_PALETTE[g].unlockDiv);
}

